// Gate 1: Freshness Check
const fs = require('fs');
let warning = null;

try {
  const changelog = fs.readFileSync('/data/references/changelog.md', 'utf8');
  const dateMatch = changelog.match(/Cập nhật.*?(\d{2}\/\d{2}\/\d{4})/i);
  if (dateMatch) {
    const parts = dateMatch[1].split('/');
    const updateDate = new Date(parts[2], parts[1]-1, parts[0]);
    const now = new Date();
    const diffMonths = (now - updateDate) / (1000*60*60*24*30);
    if (diffMonths > 6) {
      warning = '⚠️ Dữ liệu cập nhật lần cuối cách đây hơn 6 tháng, có thể đã lỗi thời.';
    }
  }
} catch(e) {}

return [{ json: { ...($input.first().json), warning } }];

const chunks = $input.all().map(i => i.json);
const message = $('Start').first().json.message;
const warning = $('Gate 1 Freshness').first().json.warning;

const topScore = chunks.length > 0 ? chunks[0].similarity : 0;
const hasGoodMatch = topScore > 0.75;

// Check multi-income (Rule 7)
const msg = message.toLowerCase();
const isMultiIncome = msg.match(/nhiều nguồn|vừa.*vừa|lương.*freelance|lương.*kinh doanh|2 nơi/);

let context = '';
if (hasGoodMatch) {
  context = chunks.map(c => `[${c.source_file}/${c.section_title}]\n${c.chunk_text}`).join('\n\n---\n\n');
} else {
  // Load full files based on keyword matching
  const fs = require('fs');
  const dir = '/data/references/';
  let files = ['tong-quan-thue.md', 'faq.md'];

  if (msg.match(/freelancer|kol|seller|bán hàng|shopee/)) files.push('freelancer-guide.md');
  if (msg.match(/expat|nước ngoài|cư trú|dta/)) files.push('nguoi-nuoc-ngoai-guide.md');
  if (msg.match(/bhxh|rút.*lần|bảo hiểm xã hội/)) files.push('bhxh-rut-mot-lan-guide.md');
  if (msg.match(/thất nghiệp|bhtn|trợ cấp/)) files.push('bhtn-tro-cap-guide.md');
  if (msg.match(/quyết toán|etax|sop|nộp thuế/)) files.push('sop-quyet-toan.md');
  if (msg.match(/hộ kinh doanh|thuế khoán|hkd/)) files.push('thue-khoan-guide.md');

  files = [...new Set(files)];
  for (const f of files) {
    try {
      context += `\n[${f}]\n` + fs.readFileSync(dir + f, 'utf8') + '\n---\n';
    } catch(e) {}
  }
}

if (isMultiIncome) {
  const fs = require('fs');
  const dir = '/data/references/';
  const extraFiles = ['tong-quan-thue.md', 'freelancer-guide.md'];
  for (const f of extraFiles) {
    if (!context.includes(f)) {
      try { context += `\n[${f}]\n` + fs.readFileSync(dir + f, 'utf8'); } catch(e) {}
    }
  }
}

const sources = [...new Set(chunks.map(c => c.source_file))];

return [{ json: { message, context, warning, sources, hasGoodMatch, isMultiIncome } }];

